select * from ( select t3.app_id, t3.bpm_title, t3.initiator_id, t3.initiator_name, t3.initiator_avatar, t3.initiator_dept_id, t3.initiator_dept_name, t3.submit_time, t3.form_summary, t3.form_name, t3.binding_view_id, t.id, t.task_id, t.instance_id, t.approver, t.collaborator, t.ext, t.flow_status as task_flow_status, t.create_time, t.update_time, t1.node_code, t1.flow_status, t4.agent_id as agent_id, t4.agent_name as agent_name, ROW_NUMBER() OVER ( PARTITION BY t.id ORDER BY CASE WHEN t.approver = #{userId} THEN 1 WHEN t4.agent_id = #{userId} THEN 2 ELSE 3 END ) as rn FROM bpm_flow_his_task t LEFT JOIN bpm_flow_instance t1 ON t.instance_id = t1.id left join bpm_flow_instance_biz_ext t3 on t.instance_id = t3.instance_id left join bpm_flow_agent_ins t4 on t.task_id = t4.task_id and t.approver = t4.principal_id and t4.deleted = 0 WHERE t1.deleted = 0 and t.deleted = 0 and t3.deleted = 0 and t.node_type = 1 and (t.approver = #{userId} or t4.agent_id = #{userId})
AND t3.app_id = #{queryVO.appId}
AND ( t3.bpm_title LIKE CONCAT('%', #{queryVO.keyword}, '%') OR t3.initiator_name LIKE CONCAT('%', #{queryVO.keyword}, '%') OR t3.form_summary LIKE CONCAT('%', #{queryVO.keyword}, '%') )
AND t3.binding_view_id = #{queryVO.businessId}
AND t1.flow_status IN
#{item}
AND t1.node_code IN
#{item}
AND t3.submit_time >= #{queryVO.submitTimeStart}
AND t3.submit_time <= #{queryVO.submitTimeEnd}
AND t3.initiator_id IN
#{item}
ORDER BY t.update_time ASC
ORDER BY t.update_time DESC
) tf where rn = 1

select * from ( select t3.app_id, t3.bpm_title, t3.initiator_id, t3.initiator_name, t3.initiator_avatar, t3.initiator_dept_id, t3.initiator_dept_name, t3.submit_time, t3.form_summary, t3.form_name, t3.binding_view_id, t.id, t.instance_id, t.flow_status, t.create_time, t1.processed_by, t1.type as user_type, t2.node_code, t4.agent_id as agent_id, t4.agent_name as agent_name, ROW_NUMBER() OVER ( PARTITION BY t.id ORDER BY CASE WHEN t1.processed_by = #{userId} THEN 1 WHEN t4.agent_id = #{userId} THEN 2 ELSE 3 END ) as rn from bpm_flow_task t left join bpm_flow_user t1 on t.id = t1.associated left join bpm_flow_instance t2 on t.instance_id = t2.id left join bpm_flow_instance_biz_ext t3 on t.instance_id = t3.instance_id left join bpm_flow_agent_ins t4 ON t.id = t4.task_id AND t1.processed_by = t4.principal_id and t4.deleted = 0 where t.node_type = 1 and t.flow_status != 'draft' and t.deleted = 0 and t1.deleted = 0 and t2.deleted = 0 and t3.deleted = 0 and (t1.processed_by = #{userId} or t4.agent_id = #{userId})
AND t3.app_id = #{queryVO.appId}
AND ( t3.bpm_title LIKE CONCAT('%', #{queryVO.keyword}, '%') OR t3.initiator_name LIKE CONCAT('%', #{queryVO.keyword}, '%') OR t3.form_summary LIKE CONCAT('%', #{queryVO.keyword}, '%') )
AND t3.binding_view_id = #{queryVO.businessId}
AND t.flow_status IN
#{item}
AND t2.node_code IN
#{item}
AND t3.submit_time >= #{queryVO.submitTimeStart}
AND t3.submit_time <= #{queryVO.submitTimeEnd}
AND t3.initiator_id IN
#{item}
ORDER BY t.create_time ASC
ORDER BY t.create_time DESC
) tf where rn = 1

select * from ( select distinct t3.app_id, t3.bpm_title, t3.initiator_id, t3.initiator_name, t3.initiator_dept_id, t3.initiator_dept_name, t3.submit_Time, t3.form_summary, t3.form_name, t3.binding_view_id, t.id, t.definition_id, t.node_type, t.node_code, t.node_name, t.flow_status, t.creator, t.create_time, t.updater, t.update_time from bpm_flow_instance t inner join bpm_flow_instance_biz_ext t3 on t.id = t3.instance_id where t.deleted = 0 and t3.deleted = 0
AND t.creator = #{userId}
